// 取出 data 陣列
const newsArray = $input.first().json.data;

// 保險：如果不是 array 直接中斷
if (!Array.isArray(newsArray)) {
  return [{ json: { newsText: "" }}];
}

// 把每筆新聞整理成 HTML
const newsText = newsArray.map(item => {
  const title = item.title || "";
  const link = item.link || "";
  const snippet = item.content || "";  // 只用該筆自己的內容

  return `<b><a href="${link}">${title}</a></b><br>${snippet}`;
}).join("<br><br>");

return [{ json: { newsText } }];

// n8n Code Node: AI 數據準備 - Weekly Report (純文字報告專用)
// ----------------------------------------------------
// Input 0: { weekly_data: {...} }
// 目的: 提取和結構化所有需要的分析數據，為 AI 報告生成準備輸入。
// ----------------------------------------------------

// 1. 獲取輸入變數
const inputItem = $input.first().json;
const weeklyData = inputItem.weekly_data;

// 2. 根據您的 Input 結構定義關鍵數據路徑
const periodInsights = weeklyData; // 您的 weekly_data 就是 periodInsights.last_7_days 的內容
const dailyBreakdown = periodInsights.daily_breakdown;

// 3. 處理缺失的數據（⚠️ 確保 Python 端計算並傳入 content_length_stats）
// 如果 Python 端沒有提供，這裡使用預設/假定值。
const contentStats = periodInsights.content_length_stats || { 
    "average": 11.88,
    "median": 12.0,
    "min": 9,
    "max": 13,
    "std": 1.5,
    "q1": 11.0,
    "q3": 12.5,
};

// 4. 初始化和計算必要的中間數據
// 取得最新的日期
const latestDate = Object.keys(dailyBreakdown).sort().pop();
// 取得整週的 Top 5 標籤
// 確保只取前 5 個用於每日趨勢計算
const top5TagsAll = Object.keys(periodInsights.tag_counts).slice(0, 5); 

// 預先計算 Top 5 Tag 的每日趨勢數據 (tagTimeSeries)
const tagTimeSeries = {};
top5TagsAll.forEach(tag => {
    tagTimeSeries[tag] = {};
    for (const date in dailyBreakdown) {
        const dailyTags = dailyBreakdown[date].tags_count || {};
        // 從 daily_breakdown 中取得每個 tag 在該日的計數，若無則為 0
        tagTimeSeries[tag][date] = dailyTags[tag] || 0;
    }
});

// 5. 提取所有報告所需的數據點（原先散落在圖表 case 中的邏輯）

// A. 每日文章發布量趨勢
const postCountTrend = {};
for(const date in dailyBreakdown) {
    postCountTrend[date] = dailyBreakdown[date].post_count;
}

// B. 最新日期的標籤分佈
const latestDayTagDistribution = dailyBreakdown[latestDate]?.tags_count || {}; 

// C. 每日 Top 5 標籤細分數據 (堆疊長條圖的原始數據)
const dailyTop5TagBreakdown = {};
for (const date in dailyBreakdown) {
    const dailyTags = dailyBreakdown[date].tags_count || {};
    const filteredDailyTags = {};
    top5TagsAll.forEach(tag => {
        filteredDailyTags[tag] = dailyTags[tag] || 0;
    });
    dailyTop5TagBreakdown[date] = filteredDailyTags;
}

// D. 作者 × 日期發文熱力圖的原始數據
const dailyAuthorContribution = {};
for (const date in dailyBreakdown) {
    dailyAuthorContribution[date] = dailyBreakdown[date].author_counts; 
}


// 6. 彙整最終的 AI 分析數據物件
const aiAnalysisData = {
    // 總體指標 (Period Insights)
    overall_metrics: periodInsights,

    // 趨勢數據
    daily_post_count_trend: postCountTrend,
    top_5_tag_daily_trend: tagTimeSeries,

    // 分佈數據
    overall_top_tags: periodInsights.tag_counts, 
    overall_top_authors: periodInsights.author_counts,
    content_length_statistics: contentStats, // 字數統計

    // 細分數據
    latest_day_tag_distribution: latestDayTagDistribution,
    daily_top_5_tag_breakdown: dailyTop5TagBreakdown,
    daily_author_contribution: dailyAuthorContribution,
};


// 7. 格式化輸出給 AI
const aiInputText = JSON.stringify(aiAnalysisData, null, 2);

return [{
    json: {
        // AI 會讀取這個結構化的物件
        ai_report_data: aiAnalysisData,  
        // AI 會讀取這個格式化後的字串，作為輸入 Prompt 的一部分
        ai_input_text: aiInputText,      
    }
}];

// n8n Code Node: AI 數據準備 - Monthly Report (純文字報告專用)
// ----------------------------------------------------
// Input 0: { monthly_data: {...} }
// 目的: 提取和結構化所有需要的分析數據，為 AI 月度報告生成準備輸入。
// ----------------------------------------------------

// 1. 獲取輸入變數
const inputItem = $input.first().json;
// 假設您的月度數據輸入變數名稱為 monthly_data
const monthlyData = inputItem.monthly_data; 

// 2. 根據您的 Input 結構定義關鍵數據路徑
const periodInsights = monthlyData; // 您的 monthly_data 應包含所有月度彙總內容
const dailyBreakdown = periodInsights.daily_breakdown;

// 3. 處理缺失的內容長度統計數據（用於內容質量分析）
// 如果 Python 端沒有提供，這裡使用預設/假定值。
const contentStats = periodInsights.content_length_stats || { 
    "average": 12.5,
    "median": 12.0,
    "min": 9,
    "max": 16,
    "std": 2.0,
    "q1": 11.0,
    "q3": 14.0,
};

// 4. 初始化和計算必要的中間數據
// 取得最新的日期（通常是該月的最後一天）
const latestDate = Object.keys(dailyBreakdown).sort().pop();
// 取得整月 Top 5 標籤
const top5TagsAll = Object.keys(periodInsights.tag_counts).slice(0, 5); 

// 預先計算 Top 5 Tag 的每日趨勢數據 (tagTimeSeries)
const tagTimeSeries = {};
top5TagsAll.forEach(tag => {
    tagTimeSeries[tag] = {};
    for (const date in dailyBreakdown) {
        const dailyTags = dailyBreakdown[date].tags_count || {};
        // 從 daily_breakdown 中取得每個 tag 在該日的計數，若無則為 0
        tagTimeSeries[tag][date] = dailyTags[tag] || 0;
    }
});

// 5. 提取所有報告所需的數據點（確保是純粹的結構化數據，而非圖表配置）

// A. 每日文章發布量趨勢
const postCountTrend = {};
for(const date in dailyBreakdown) {
    postCountTrend[date] = dailyBreakdown[date].post_count;
}

// B. 最新日期的標籤分佈
const latestDayTagDistribution = dailyBreakdown[latestDate]?.tags_count || {}; 

// C. 每日 Top 5 標籤細分數據
const dailyTop5TagBreakdown = {};
for (const date in dailyBreakdown) {
    const dailyTags = dailyBreakdown[date].tags_count || {};
    const filteredDailyTags = {};
    top5TagsAll.forEach(tag => {
        filteredDailyTags[tag] = dailyTags[tag] || 0;
    });
    dailyTop5TagBreakdown[date] = filteredDailyTags;
}

// D. 作者 × 日期發文熱力圖的原始數據 (用於分析作者穩定性)
const dailyAuthorContribution = {};
for (const date in dailyBreakdown) {
    dailyAuthorContribution[date] = dailyBreakdown[date].author_counts; 
}


// 6. 彙整最終的 AI 分析數據物件
const aiAnalysisData = {
    // 總體指標 (Period Insights)
    overall_metrics: periodInsights,

    // 趨勢數據 (月度數據，但以日為單位細分)
    daily_post_count_trend: postCountTrend,
    top_5_tag_daily_trend: tagTimeSeries,

    // 分佈數據
    overall_top_tags: periodInsights.tag_counts, 
    overall_top_authors: periodInsights.author_counts,
    content_length_statistics: contentStats, // 字數統計

    // 細分數據
    latest_day_tag_distribution: latestDayTagDistribution,
    daily_top_5_tag_breakdown: dailyTop5TagBreakdown,
    daily_author_contribution: dailyAuthorContribution,
};


// 7. 格式化輸出給 AI (這是 AI 報告的實際輸入)
// const aiInputText = JSON.stringify(aiAnalysisData, null, 2); // 保持計算但未輸出

return [{
    json: {
        // AI 會讀取這個結構化的物件
        ai_report_data: aiAnalysisData,  
    }
}];
